head.script:
scwin.selpchClsCd = "1";
scwin.MSG_FS_WRN_013 = "청구 데이타가 존재하지 않습니다.";
scwin.MSG_FS_WRN_014 = "청구취소 데이타가 존재하지 않습니다.";
scwin.MSG_FS_WRN_015 = "청구는 내부거래상태가 등록일때만 가능합니다.";
scwin.MSG_FS_WRN_016 = "청구취소는 내부거래상태가 청구일때만 가능합니다.";
scwin.flag = "";
scwin.bizDom = "";
scwin.vLoginCoCd = "";
scwin.vLoginCoClsCd = "";
scwin.vUserHomeClsCd = "";
scwin.isSubCompany = false;
scwin.quantityOfRows = "";
scwin.pageNumber = "1";
scwin.vCoCd = "";
scwin.vCoClsCd = "";
scwin.vCurDate = "";
scwin.strPreDate = "";
scwin.txtCoClsCd = "";
scwin.selPchLodeptCd = "";
scwin.qryConDt = "";
scwin.qryConLastDt = "";
scwin.strbilgClntNo = "";
scwin.strbilgClntNm = "";
scwin.strlobranCd = "";
scwin.strlobranNm = "";
scwin.privAdmin = "";
scwin.ACConstants_SUBSIDIARY_USER_HOME_CLS_CD = "";
scwin.ACConstants_CO_CD_DONGBU = "";
scwin.ACConstants_CO_CLS_CD_DONGBU = "";

scwin.onpageload = async function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strPreDate = scwin.vCurDate.substring(0, 6) + "01";

    scwin.vLoginCoCd = $c.ses.getCoCd() || "";
    scwin.vLoginCoClsCd = $c.ses.getCoClsCd() || "";
    scwin.vUserHomeClsCd = $c.ses.getUserHomeClsCd() || "";
    scwin.vCoCd = scwin.vLoginCoCd;
    scwin.vCoClsCd = scwin.vLoginCoClsCd;
    scwin.privAdmin = $c.ses.getPrivAdmin() || "";

    scwin.ACConstants_SUBSIDIARY_USER_HOME_CLS_CD = "SA";
    scwin.ACConstants_CO_CD_DONGBU = "001";
    scwin.ACConstants_CO_CLS_CD_DONGBU = "0";

    let params = $c.data.getParameter();
    if (params != null) {
        scwin.flag = params["flag"] || "";
        scwin.bizDom = params["bizDom"] || "";
        scwin.selPchLodeptCd = params["selPchLodeptCd"] || "";
        scwin.qryConDt = params["qryConDt"] || "";
        scwin.qryConLastDt = params["qryConLastDt"] || "";
        scwin.strbilgClntNo = params["bilgClntNo"] || "";
        scwin.strbilgClntNm = params["bilgClntNm"] || "";
        scwin.strlobranCd = params["strlobranCd"] || "";
        scwin.strlobranNm = params["strlobranNm"] || "";
    }
};

scwin.onUdcCompleted = async function() {
    acb_gubun1.setValue("RSLTS_DT");
    udc_rsltsDt.setInitDate(scwin.strPreDate, scwin.vCurDate);
    ed_bilgClntNo.setValue(scwin.strbilgClntNo);
    txt_bilgClntNm.setValue(scwin.strbilgClntNm);
    ed_bilgLodeptCd.setValue(scwin.strlobranCd);
    txt_bilgLodeptNm.setValue(scwin.strlobranNm);

    scwin.f_setCompanyInfo();

    if (scwin.flag != "") {
        scwin.f_WholeRetrieve();
    }

    if (scwin.selPchLodeptCd != "") {
        scwin.f_executeFromLinked();
    }
};

scwin.f_setCompanyInfo = async function() {
    if (scwin.vUserHomeClsCd != scwin.ACConstants_SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = scwin.ACConstants_CO_CD_DONGBU;
        scwin.vLoginCoClsCd = scwin.ACConstants_CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo("T");

    if ("T" == scwin.privAdmin || !scwin.isSubCompany) {
        $c.gus.cfEnableObjects([ed_coCd, txt_coNm]);
    } else {
        $c.gus.cfDisableObjects([ed_coCd, txt_coNm]);
    }
};

scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    udc_co.ilCommonPopUp(scwin.callbackCompanyInfo,
        ed_coCd.getValue(), txt_coNm.getValue(),
        pWinCloseTF, null, null, null, null,
        null, null, null, null, null);
};

scwin.callbackCompanyInfo = async function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);
        txt_coNm.setValue(rtnList[5]);
        scwin.txtCoClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        txt_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > scwin.ACConstants_CO_CLS_CD_DONGBU) {
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }
};

scwin.f_initObj = async function() {
    $c.gus.cfInitObjects([ed_bilgLodeptCd, txt_bilgLodeptNm]);
    $c.gus.cfInitObjects([ed_bilgClntNo, txt_bilgClntNm]);
};

scwin.f_executeFromLinked = async function() {
    ed_bilgLodeptCd.setValue(scwin.selPchLodeptCd);
    ica_rsltsDtSt.setValue(scwin.qryConDt + "01");
    ica_rsltsDtEnd.setValue(scwin.qryConLastDt);
    scwin.f_RetrieveCustomerEachUnityPurchase();
};

scwin.f_WholeRetrieve = async function() {
    ed_bilgLodeptCd.setValue(dma_selldecunsetaggr_con.get("bilgLodeptCd"));
    scwin.f_openCommonPopUp(1, ed_bilgLodeptCd.getValue(), txt_bilgLodeptNm.getValue(), "T", "T");
    ica_rsltsDtSt.setValue(dma_selldecunsetaggr_con.get("qryConDtFm"));
    ica_rsltsDtEnd.setValue(dma_selldecunsetaggr_con.get("qryConDtTo"));
    scwin.f_RetrieveCustomerEachUnityPurchase();
};

scwin.f_RunExcel = async function(value) {
    let gridId = "";
    let sheetName = "";
    let fileName = "";

    if (value == "A") {
        let countA = ds_customerEachUnityPurchaseList.getRowCount();
        if (!(countA > 0)) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            return;
        }
        gridId = "gr_customerEachUnityPurchaseList";
        sheetName = "거래처별 매입 현황 ";
        fileName = "거래처별 매입 현황.xlsx";
    } else if (value == "B") {
        let countB = ds_orderEachUnityPurchaseList.getRowCount();
        if (!(countB > 0)) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            return;
        }
        gridId = "gr_orderEachUnityPurchaseList";
        sheetName = "오더별 매입 현황 ";
        fileName = "오더별 매입 현황.xlsx";
    }

    let chk = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (chk) {
        $c.data.downloadGridViewExcel(gridId, {"fileName": fileName, "sheetName": sheetName});
    }
};

scwin.f_RetrieveCustomerEachUnityPurchase = async function() {
    let chkValid = await $c.gus.cfValidate([ed_bilgLodeptCd, ica_rsltsDtSt, ica_rsltsDtEnd]);
    if (!chkValid) {
        return;
    }

    let gubunVal = acb_gubun1.getValue();
    if (gubunVal == "RSLTS_DT" || gubunVal == "ODR_DT" || gubunVal == "INTEND_DT" || gubunVal == "POST_DT") {
        let chkDate = await $c.gus.cfValidate([ica_rsltsDtSt, ica_rsltsDtEnd]);
        if (!chkDate) {
            return;
        }
        if (!$c.gus.cfIsAfterDate(ica_rsltsDtSt.getValue(), ica_rsltsDtEnd.getValue())) {
            await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ica_rsltsDtSt.setFocus();
            return;
        }
    }

    dma_selldecunsetaggr_con.set("coCd", ed_coCd.getValue());
    dma_selldecunsetaggr_con.set("gubun1", acb_gubun1.getValue());
    dma_selldecunsetaggr_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
    dma_selldecunsetaggr_con.set("pchsDeptCd", ed_bilgLodeptCd.getValue());
    dma_selldecunsetaggr_con.set("odrNo", "");
    dma_selldecunsetaggr_con.set("bilgClntNo", ed_bilgClntNo.getValue());
    dma_selldecunsetaggr_con.set("pchsClntNo", ed_bilgClntNo.getValue());
    dma_selldecunsetaggr_con.set("rsltsDtSt", ica_rsltsDtSt.getValue());
    dma_selldecunsetaggr_con.set("rsltsDtEnd", ica_rsltsDtEnd.getValue());
    dma_selldecunsetaggr_con.set("regId", ed_regId.getValue());
    dma_selldecunsetaggr_con.set("modId", ed_modId.getValue());
    dma_selldecunsetaggr_con.set("aggbilgClntNo", ed_bilgClntNo.getValue());
    await $c.sbm.execute(sbm_queryConditionDTO);
};

scwin.f_save = async function() {
    let chk = await $c.win.confirm(MSG_CM_CRM_001);
    if (chk) {
        if (ds_orderEachUnityPurchaseList.getUpdatedIndex().length > 0) {
            let checkedCnt = 0;
            for (let i = 0; i < ds_orderEachUnityPurchaseList.getRowCount(); i++) {
                if (ds_orderEachUnityPurchaseList.getCellData(i, "chk") == "T") {
                    checkedCnt++;
                    break;
                }
            }

            if (checkedCnt == 0) {
                await $c.win.alert("체크된 데이터가 없습니다.");
                return false;
            }
            let chkValid = await $c.gus.cfValidate([gr_orderEachUnityPurchaseList]);
            if (chkValid) {
                await $c.sbm.execute(sbm_savePchsInfo);
            }
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["통합매입일괄수정"]);
        }
    }
};

scwin.f_openOdrNoPopUp = async function() {
    let args = {};
    args.odrNo = "";
    let rtnValues = await $c.win.openPopup("/ui/ja/ds/sd/odrmgnt/odrreg/ja_sd_402_01_26p.xml", {
        width: 820,
        height: 510,
        modal: true,
        data: args
    });
    if (rtnValues != null) {
        // TODO: ed_odrNo 는 body에 없으므로 별도 처리 필요
    }
};

scwin.f_openPopUpGrid = async function(ds, cdColid, nmColid, gubun, pWinCloseTF) {
    let pCode = "";
    let pName = "";
    let pWtitleSearch = null;
    let pDispCnt = null;
    let pHidden = null;
    let pWhere = null;

    switch (gubun) {
        case 1:
            pCode = ds.getCellData(ds.getRowPosition(), cdColid);
            pName = ds.getCellData(ds.getRowPosition(), nmColid);
            let param = ",,," + ed_coCd.getValue();

            if (gubun == 1) {
                let pSelectID = "retrieveAcctDeptCdInfo10";
                pWtitleSearch = "매입처,매입처코드,매입처";
                pWhere = null;
            }

            udc_comCode_Grid.ilCommonPopUp(function(rtnList) {
                if (rtnList != null) {
                    if (rtnList[0] == "N/A") {
                        ds.setCellData(ds.getRowPosition(), cdColid, ds.getOrgCellData(ds.getRowPosition(), cdColid));
                        ds.setCellData(ds.getRowPosition(), nmColid, ds.getOrgCellData(ds.getRowPosition(), nmColid));
                    } else {
                        ds.setCellData(ds.getRowPosition(), cdColid, rtnList[0]);
                        ds.setCellData(ds.getRowPosition(), nmColid, rtnList[1]);
                        ds.setCellData(ds.getRowPosition(), "chk", "T");
                    }
                } else {
                    ds.setCellData(ds.getRowPosition(), cdColid, "");
                    ds.setCellData(ds.getRowPosition(), nmColid, "");
                }
            },
            pCode, pName, pWinCloseTF, pDispCnt, null, null, pHidden, param,
            null, null, null, null, null, "F", pWtitleSearch);
            break;

        case 2:
            pCode = "";
            pName = ds.getCellData(ds.getRowPosition(), nmColid);
            pWhere = ds_orderEachUnityPurchaseList.getCellData(ds_orderEachUnityPurchaseList.getRowPosition(), "pchsClntNo");

            udc_comCode_Grid.ilCommonPopUp(function(rtnList) {
                // TODO: 원본에서 주석처리된 콜백 로직
            },
            pCode, pName, "F", null, null, null, null, pWhere,
            null, null, null, null, null, null, null);
            break;

        default:
            break;
    }
};

scwin.f_changeSellInfoWhole = async function() {
    let stPos = ds_orderEachUnityPurchaseList.getRowPosition();
    let pchsClntNo = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNo");
    let pchsClntNm = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNm");

    for (let i = stPos; i < ds_orderEachUnityPurchaseList.getRowCount(); i++) {
        if (ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") != "1") {
            await $c.gus.cfAlertMsg("미확인 내역만 수정이 가능합니다.", []);
            return false;
        }

        if (ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") == "1") {
            ds_orderEachUnityPurchaseList.setCellData(i, "chk", "T");
        }

        let focusedCol = gr_orderEachUnityPurchaseList.getFocusedColumnID ? gr_orderEachUnityPurchaseList.getFocusedColumnID() : "";
        if (focusedCol == "pchsClntNo" || focusedCol == "pchsClntNm") {
            ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNo", pchsClntNo);
            ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNm", pchsClntNm);
        }
    }
    return true;
};

scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let clntNo = ed_bilgClntNo.getValue();

    switch (disGubun) {
        case 1:
            udc_bilgLodept.ilCommonPopUp(scwin.callbackBilgLodept,
                (pCode || "").trim(), pName, pClose, null, null, null, null,
                null, null, null, null, null, null, pAllSearch, null);
            break;

        case 2:
            let param2 = ",,," + ed_coCd.getValue();
            udc_bilgClnt.ilCommonPopUp(scwin.callbackBilgClnt,
                ed_bilgClntNo.getValue().trim(), txt_bilgClntNm.getValue(), pClose, null, null, null, null,
                param2, null, null, null, null);
            break;

        case 3:
            break;

        case 5:
            udc_comCode_Grid.ilCommonPopUp(scwin.callbackCommInfo,
                (pCode || "").trim(), pName, pClose, null, null, null, null,
                ",,4,," + clntNo, null, null, null, null, null, pAllSearch, "품명,품명코드,품명");
            break;

        case 6:
            udc_comCode_Grid.ilCommonPopUp(scwin.callbackBlNo,
                (pCode || "").trim(), pName, pClose, null, null, null, null,
                null, null, null, null, null, null, pAllSearch, null);
            break;

        case 7:
            udc_comCode_Grid.ilCommonPopUp(function(rtnList) {},
                (pCode || "").trim(), pName, pClose, null, null, null, null,
                ",,3,," + clntNo, null, null, null, null, null, pAllSearch, "품목,품목코드,품목");
            break;

        case 10:
            udc_comCode_Grid.ilCommonPopUp(scwin.callbackSellItem,
                (pCode || "").trim(), pName, pClose, null, null, null, null,
                null, null, null, null, null, null, pAllSearch, null);
            break;

        case 11:
            udc_reg.ilCommonPopUp(scwin.callbackRegId,
                pCode, pName, pClose, null, null, null, null,
                scwin.vCoCd, null, null, null, null, null, pAllSearch,
                "등록자,사용자ID,사용자명");
            break;

        case 14:
            udc_comCode_Grid.ilCommonPopUp(function(rtnList) {},
                (pCode || "").trim(), pName, pClose, null, null, null, null,
                "1", null, null, null, null, null, pAllSearch, null);
            break;

        case 15:
            udc_mod.ilCommonPopUp(scwin.callbackModId,
                pCode, pName, pClose, null, null, null, null,
                scwin.vCoCd, null, null, null, null, null, pAllSearch,
                "등록자,사용자ID,사용자명");
            break;

        default:
            break;
    }
};

scwin.callbackBilgLodept = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgLodeptCd, txt_bilgLodeptNm);
};

scwin.callbackBilgClnt = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgClntNo, txt_bilgClntNm);
};

scwin.callbackCommInfo = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        // TODO: ed_qryConCd2, txt_qryConNm2 not in body — 원본에서 cfSetReturnValue(rtnList, ed_qryConCd2, txt_qryConNm2) 호출
        $c.gus.cfSetReturnValue(rtnList, null, null);
    }
};

scwin.callbackBlNo = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        // TODO: ed_qryConCd3 not in body — 원본에서 cfSetValue(ed_qryConCd3, rtnList[1]), cfSetHiddenValue(ed_qryConCd3, rtnList[1]) 호출
    }
};

scwin.callbackSellItem = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        // TODO: ed_sellItemCd, txt_sellItemNm not in body — 원본에서 cfSetReturnValue(rtnList, ed_sellItemCd, txt_sellItemNm) 호출
        $c.gus.cfSetReturnValue(rtnList, null, null);
    }
};

scwin.f_resultPopEd = function(strCdObj, strNmObj, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            return;
        }
        strCdObj.setValue(rtnList[0]);
        strNmObj.setValue(rtnList[1]);
    } else {
        strCdObj.setValue("");
        strNmObj.setValue("");
    }
};

scwin.callbackRegId = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_regId, txt_regNm);
};

scwin.callbackModId = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_modId, txt_modNm);
};

scwin.f_RetrieveOrderEachUnityPurchase = async function(row) {
    let rowIdx = (typeof row === "string") ? parseInt(row, 10) - 1 : row;
    if (rowIdx < 0) rowIdx = 0;
    dma_selldecunsetaggr_con.set("pchsClntNoDtl", ds_customerEachUnityPurchaseList.getCellData(rowIdx, "pchsClntNo"));

    if (chb_totalYn.getValue() != "") {
        dma_selldecunsetaggr_con.set("totalYn", "B");
    } else {
        dma_selldecunsetaggr_con.set("totalYn", "A");
    }

    await $c.sbm.execute(sbm_queryConditionDTODtl);
};

scwin.f_openPopUp = function(flag, check) {
    let qryYear = ica_rsltsDtSt.getValue().trim().substring(0, 4);

    switch (flag) {
        case "1":
            let temp = ",,";
            udc_comCode_Grid.ilCommonPopUp(function(rtnList) {
                scwin.f_resultPopEd("ed_acctCdSt", "txt_acctCdStNm", rtnList);
            },
            "", "", check, null, null, null, null, temp, null, null, null, null);
            break;

        case "3":
            let param3 = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0";
            udc_bilgLodept.ilCommonPopUp(function(rtnList) {
                scwin.f_resultPopEd(ed_bilgLodeptCd, txt_bilgLodeptNm, rtnList);
            },
            ed_bilgLodeptCd.getValue().trim(), txt_bilgLodeptNm.getValue(), check,
            null, null, null, null, param3, null, null, null, null, null, null, null, null, null, qryYear);
            break;

        case "4":
            let param4 = ",,," + ed_coCd.getValue();
            udc_bilgClnt.ilCommonPopUp(function(rtnList) {
                scwin.f_resultPopEd(ed_bilgClntNo, txt_bilgClntNm, rtnList);
            },
            ed_bilgClntNo.getValue().trim(), txt_bilgClntNm.getValue(), check,
            null, null, null, null, param4, null, null, null, null);
            break;

        case "8":
            let param8 = "";
            let selectID8 = "retrieveCrnInfo";
            udc_comCode_Grid.ilCommonPopUp(function(rtnList) {
                // TODO: ed_crn, txt_crnNm not in body
                if (rtnList != null) {
                    if (rtnList[0] == "N/A") return;
                }
            },
            "", "", check, null, null, null, null, param8, null, null, null, null);
            break;

        default:
            break;
    }
};

scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    else
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
};

scwin.f_deptPopUp = async function() {
    let param = scwin.vCurDate;

    if (scwin.vCoClsCd > scwin.ACConstants_CO_CLS_CD_DONGBU) {
        param = param + "," + scwin.vCoCd + "," + scwin.vCoClsCd;
    }
    let paramArray = {};
    paramArray.pSelectID = "retrieveAcctDeptCdInfo6";
    paramArray.pCode = ed_bilgLodeptCd;
    paramArray.pName = txt_bilgLodeptNm;
    paramArray.pWhere = param;
    scwin.f_PopUp2(paramArray);
};

scwin.f_PopUp2 = async function(paramArray) {
    let codeObj = paramArray.pCode;
    let nameObj = paramArray.pName;

    udc_bilgLodept.ilCommonPopUp(function(rtnList) {
        if (rtnList != null) {
            if (rtnList[0] != "N/A") {
                $c.gus.cfSetValue(codeObj, rtnList[0]);
                $c.gus.cfSetValue(nameObj, rtnList[1]);
            }
        } else {
            $c.gus.cfSetValue(codeObj, "");
            $c.gus.cfSetValue(nameObj, "");
        }
    },
    $c.gus.cfGetValue(codeObj), "",
    scwin.f_EventCheck(), paramArray.pDispCnt,
