scwin.f_changeSellInfoWholeChecked = async function() {
    let stPos = ds_orderEachUnityPurchaseList.getRowPosition();
    let pchsClntNo = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNo");
    let pchsClntNm = ds_orderEachUnityPurchaseList.getCellData(stPos, "pchsClntNm");

    for (let i = stPos; i < ds_orderEachUnityPurchaseList.getRowCount(); i++) {
        if (ds_orderEachUnityPurchaseList.getCellData(i, "chk") == "T") {
            if (ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") != "1") {
                await $c.gus.cfAlertMsg("미확인 내역만 수정이 가능합니다.", []);
                return false;
            }

            if (ds_orderEachUnityPurchaseList.getCellData(i, "dcsnClsCd") == "1") {
                ds_orderEachUnityPurchaseList.setCellData(i, "chk", "T");
            }

            let focusedCol = gr_orderEachUnityPurchaseList.getFocusedColumnID ? gr_orderEachUnityPurchaseList.getFocusedColumnID() : "";
            if (focusedCol == "pchsClntNo" || focusedCol == "pchsClntNm") {
                ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNo", pchsClntNo);
                ds_orderEachUnityPurchaseList.setCellData(i, "pchsClntNm", pchsClntNm);
            }
        }
    }
    return true;
};

scwin.f_grdHeight = function(size, objGrdId) {
    let objGrd = WebSquare.util.getComponentById(objGrdId);
    if (objGrd) {
        let strHeight = objGrd.style.height;
        let intHeight = parseInt(strHeight.replace("px", ""));
        intHeight = intHeight + size;
        if (intHeight > 0) {
            objGrd.style.height = intHeight + "px";
        }
    }
};

scwin.f_downExcelSheet = async function(vObjGrdId) {
    let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
        $c.data.downloadGridViewExcel(vObjGrdId, {"fileName": "통합매출상세.xlsx", "sheetName": "통합매출상세"});
    }
};

scwin.dataSetDebug = async function(dataList, isDebug) {
    if (isDebug == true) {
        let obj = dataList;
        let str = "[[[[" + obj.getID() + "]]]]]\n";
        for (let dsRow = 0; dsRow < obj.getRowCount(); dsRow++) {
            let colInfos = obj.getColumnIDs ? obj.getColumnIDs() : [];
            for (let dsCol = 0; dsCol < colInfos.length; dsCol++) {
                str += "[" + colInfos[dsCol] + "] " + obj.getCellData(dsRow, colInfos[dsCol]) + ", ";
            }
            str += "\n\n";
        }
        await $c.win.alert(str);
    }
};

