scwin.f_openPopUpGridBefore = function(colGubun, ds, cdColid, nmColid, olddata, gubun, pWinCloseTF) {
    if (colGubun == "CD") {
        let cdVal = ds.getCellData(ds.getRowPosition(), cdColid);
        if (cdVal == "") {
            ds.setCellData(ds.getRowPosition(), nmColid, "");
        } else {
            let nmVal = ds.getCellData(ds.getRowPosition(), nmColid);
            if (nmVal != olddata) {
                ds.setCellData(ds.getRowPosition(), nmColid, "");
                scwin.f_openPopUpGrid(ds, cdColid, nmColid, gubun, pWinCloseTF);
            }
        }
    } else if (colGubun == "NM") {
        let nmVal = ds.getCellData(ds.getRowPosition(), nmColid);
        if (nmVal == "") {
            ds.setCellData(ds.getRowPosition(), cdColid, "");
        } else {
            if (nmVal != olddata) {
                ds.setCellData(ds.getRowPosition(), cdColid, "");
                scwin.f_openPopUpGrid(ds, cdColid, nmColid, gubun, pWinCloseTF);
            }
        }
    }
};

scwin.f_IsPopUp = function(inObj) {
    let inValue = $c.gus.cfGetValue(inObj);
    let hidValue = inObj.getUserData ? inObj.getUserData("hidVal") : "";

    if ($c.gus.cfIsNull(inValue)) {
        if (inObj.setUserData) inObj.setUserData("hidVal", "");
        for (let i = 1; i < arguments.length; i++) {
            $c.gus.cfSetValue(arguments[i], "");
        }
        return false;
    }
    if (inValue == hidValue)
        return false;

    return true;
};

